#include <bits/stdc++.h>
using namespace std;
const int N=100005;
int n,m,a[N],tree[N];
int fun(int x)
{
	int sum=0;
	for(int i=x;i>0;i-=(i&(-i))) sum+=tree[i];
	return sum;
}
void add(int x,int k)
{
	for(int i=x;i<=n;i+=(i&(-i))) tree[i]+=k;
}
int main()
{
	cin>>n>>m;
	while(m--) 
	{
		int op;
		cin>>op;
		if(op==1)
		{
			int x,y;
			cin>>x>>y;
			add(x,1);
			add(y+1,-1);
		}
		else
		{
			int x;
			cin>>x;
			cout<<fun(x)%2<<'\n';
		}
	}
	return 0;
}
